import { supabase, isSupabaseConfigured } from './supabaseClient';

const SESSION_KEY = 'tm_session';
const missingConfigError = {
  ok: false,
  error: 'Supabase is not configured. Add REACT_APP_SUPABASE_URL and REACT_APP_SUPABASE_ANON_KEY to .env.local.',
};

function saveSession(user) {
  const session = {
    id: user.id,
    name: user.name || user.user_metadata?.name || user.email.split('@')[0],
    email: user.email,
    avatar: (user.name || user.user_metadata?.name || user.email.split('@')[0]).slice(0,2).toUpperCase(),
  };
  localStorage.setItem(SESSION_KEY, JSON.stringify(session));
  return session;
}

export async function register(name, email, password) {
  if (!isSupabaseConfigured || !supabase) return missingConfigError;
  const { data, error } = await supabase.auth.signUp({
    email,
    password,
    options: { data: { name } },
  });
  if (error) return { ok: false, error: error.message };
  const user = data.user;
  const session = saveSession({ ...user, name });
  return { ok: true, user: session };
}

export async function login(email, password) {
  if (!isSupabaseConfigured || !supabase) return missingConfigError;
  const { data, error } = await supabase.auth.signInWithPassword({
    email,
    password,
  });
  if (error) return { ok: false, error: error.message };
  const user = data.user;
  if (!user) return { ok: false, error: 'Login failed' };
  const session = saveSession(user);
  return { ok: true, user: session };
}

export async function logout() {
  if (supabase) await supabase.auth.signOut();
  localStorage.removeItem(SESSION_KEY);
}

export function getSession() {
  try { return JSON.parse(localStorage.getItem(SESSION_KEY)); }
  catch { return null; }
}
